INSERT INTO public.profiles (user_id, full_name, department, account_status) VALUES ('fba4819e-9039-49c2-83b4-1da50ccb35c3', 'Sama Larry', 'Informatique', 'active') ON CONFLICT (user_id) DO NOTHING; INSERT INTO public.user_roles (user_id, role) VALUES ('fba4819e-9039-49c2-83b4-1da50ccb35c3', 'establishment_admin') ON CONFLICT (user_id, role) DO NOTHING; INSERT INTO public.profiles (user_id, full_name, department, account_status) SELECT u.id, COALESCE(u.raw_user_meta_data->>'full_name', ''), COALESCE(u.raw_user_meta_data->>'department', ''), 'active' FROM auth.users u LEFT JOIN public.profiles p ON p.user_id = u.id WHERE p.user_id IS NULL; INSERT INTO public.user_roles (user_id, role) SELECT u.id, 'student'::app_role FROM auth.users u LEFT JOIN public.user_roles ur ON ur.user_id = u.id WHERE ur.user_id IS NULL;